INSERT INTO "problem" VALUES(157,16,'differentiate under the integral sign',NULL,NULL,NULL,'\frac{d}{dt} \int_{0}^{1} e^{t x} \, dx',NULL,NULL,'\begin{cases} \frac{\left(t - 1\right) e^{t} + 1}{t^{2}} & \text{for}\: \left(t > -\infty \vee t > 0\right) \wedge \left(t > -\infty \vee t < \infty\right) \wedge \left(t > 0 \vee t < 0\right) \wedge \left(t < 0 \vee t < \infty\right) \\\frac{1}{2} & \text{for}\: t \geq 0 \end{cases}','sympy','claude','sympy','approved',0,'medium',1,0,0,'2026-06-28T18:44:22.472022+00:00','2026-06-28T18:50:08.727053+00:00');
